// PII scrubber (espelho de backend/app/services/pii.py)
const items = $input.all();
const out = [];
const patterns = [
  { label: 'email',    re: /\b[\w.+-]+@[\w-]+\.[\w.-]+\b/g },
  { label: 'data',     re: /\b\d{2}[\/\-\.]\d{2}[\/\-\.]\d{4}\b|\b\d{4}-\d{2}-\d{2}\b/g },
  { label: 'placa',    re: /\b[A-Z]{3}-?\d[A-Z]\d{2}\b|\b[A-Z]{3}-?\d{4}\b/g },
  { label: 'cnpj',     re: /\b\d{2}\.?\d{3}\.\d{3}\/\d{4}-?\d{2}\b/g },
  { label: 'cpf',      re: /\b\d{3}\.\d{3}\.\d{3}-?\d{2}\b/g },
  { label: 'pis',      re: /\b\d{3}\.\d{5}\.\d{3}\b/g },
  { label: 'rg',       re: /\b\d{1,2}\.\d{3}\.?\d{3}-?[\dxX]\b/g },
  { label: 'titulo',   re: /\b\d{4}\s?\d{4}\s?\d{4}\b/g },
  { label: 'phone_br', re: /(?:\+?55\s?)?\(?\d{2}\)?\s?9?\d{4}[\s-]?\d{4}/g },
  { label: 'cep',      re: /\b\d{5}-?\d{3}\b/g },
  { label: 'cartao',   re: /\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b|\b\d{4}[\s-]?\d{6}[\s-]?\d{5}\b/g }
];
for (const item of items) {
  const raw = (item.json.raw_text || '').toString();
  let scrubbed = raw;
  const findings = {};
  let cnt = 0;
  for (const p of patterns) {
    const m = scrubbed.match(p.re);
    if (m && m.length) {
      findings[p.label] = m.length;
      cnt += m.length;
      scrubbed = scrubbed.replace(p.re, '[' + p.label.toUpperCase() + '_REDACTED]');
    }
  }
  const blocked = cnt > 0;
  out.push({
    json: {
      sender: item.json.sender || 'unknown',
      instance: item.json.instance || 'cartorio-2notas-uberlandia',
      scrubbed: scrubbed,
      findings: findings,
      redaction_count: cnt,
      blocked: blocked,
      consent_granted: !blocked,
      timestamp: new Date().toISOString()
    }
  });
}
return out;

