const items = $input.all();
const out = [];
for (const item of items) {
  const scrub = item.json;
  const llm = (scrub.body && scrub.body.response) ? scrub.body : scrub;
  let r;
  if (scrub.blocked === true || scrub.redaction_count > 0) {
    r = {
      status: 'pii_blocked',
      response: 'Detectei dados pessoais na sua mensagem (CPF, RG ou documento). Por questao de seguranca e conformidade com a LGPD, vou transferir seu atendimento para um escrevente humano. Aguarde.',
      sender: scrub.sender,
      pii_blocked: true,
      pii_redaction_count: scrub.redaction_count,
      needs_human_handoff: true,
      model: null,
      tokens_in: null,
      tokens_out: null,
      latency_ms: null,
      provider: 'handoff_humano'
    };
  } else {
    const ok = llm && llm.status === 'ok' && llm.response;
    r = {
      status: ok ? 'ok' : 'llm_error',
      response: ok ? llm.response : 'Desculpe, nao consegui processar sua mensagem. Um atendente humano ira retornar.',
      sender: scrub.sender,
      pii_blocked: false,
      pii_redaction_count: 0,
      needs_human_handoff: !ok,
      model: (llm && llm.model) || 'deepseek-v4-flash',
      tokens_in: (llm && llm.tokens_in) || null,
      tokens_out: (llm && llm.tokens_out) || null,
      latency_ms: (llm && llm.latency_ms) || null,
      provider: (llm && llm.config && llm.config.provider) || 'opencode_go'
    };
  }
  out.push({ json: r });
}
return out;
